import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom';
import { format } from 'date-fns';
import { vi } from 'date-fns/locale';
import './Header.css';

const routeTitles = {
  '/':          { title: 'Dashboard', subtitle: 'Tổng quan học tập' },
  '/tasks':     { title: 'Bài tập',   subtitle: 'Quản lý bài tập'   },
  '/todo':      { title: 'To-do List',subtitle: 'Việc cần làm'      },
  '/documents': { title: 'Tài liệu',  subtitle: 'Tài liệu học tập'  },
  '/notes':     { title: 'Ghi chép',  subtitle: 'Ghi chú bài học'   },
};

export default function Header({ onAddTask, onMenuToggle }) {
  const { pathname } = useLocation();
  const { title, subtitle } = routeTitles[pathname] || routeTitles['/'];
  const [now, setNow] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(timer);
  }, []);

  const timeStr = format(now, "HH:mm");
  const dateStr = format(now, "dd/MM", { locale: vi });

  return (
    <header className="header">
      <div className="header-left">
        {/* Hamburger for mobile */}
        <button
          className="header-hamburger"
          onClick={onMenuToggle}
          aria-label="Mở menu"
          id="btn-hamburger"
        >
          <span /><span /><span />
        </button>

        <div className="header-title-wrap">
          <h1 className="header-title">{title}</h1>
          <p className="header-subtitle">{subtitle}</p>
        </div>
      </div>

      <div className="header-right">
        {pathname === '/tasks' && (
          <button
            className="btn btn-primary btn-add-task"
            onClick={onAddTask}
            id="btn-add-task"
          >
            <span className="btn-add-icon">＋</span>
            <span className="btn-add-label">Thêm bài tập</span>
          </button>
        )}
        <div className="header-datetime">
          <span className="header-time">{timeStr}</span>
          <span className="header-date">{dateStr}</span>
        </div>
      </div>
    </header>
  );
}
